package businessacceptance

import (
	"crypto/sha256"
	"encoding/base64"
	"encoding/binary"
	"fmt"
	"os"
	"path/filepath"
)

const (
	acceptanceSpeechFixtureSHA256 = "4c9427131a168f7a31203530fd90734e221d928963c229faceb5dcc117d1316a"
	acceptanceSpeechFixtureBase64 = ``
)

const (
	fixtureSampleRate = 48_000
	fixtureFrames     = 4_800
	fixtureChannels   = 2
	fixtureSampleSize = 2
)

func WriteAudioFixture(path string) error {
	if !filepath.IsAbs(path) || filepath.Clean(path) != path || filepath.Ext(path) != ".wav" {
		return fmt.Errorf("acceptance audio fixture path must be a clean absolute .wav path")
	}
	dataBytes := fixtureFrames * fixtureChannels * fixtureSampleSize
	data := make([]byte, 44+dataBytes)
	copy(data[0:4], "RIFF")
	binary.LittleEndian.PutUint32(data[4:8], uint32(36+dataBytes))
	copy(data[8:12], "WAVE")
	copy(data[12:16], "fmt ")
	binary.LittleEndian.PutUint32(data[16:20], 16)
	binary.LittleEndian.PutUint16(data[20:22], 1)
	binary.LittleEndian.PutUint16(data[22:24], fixtureChannels)
	binary.LittleEndian.PutUint32(data[24:28], fixtureSampleRate)
	binary.LittleEndian.PutUint32(data[28:32], fixtureSampleRate*fixtureChannels*fixtureSampleSize)
	binary.LittleEndian.PutUint16(data[32:34], fixtureChannels*fixtureSampleSize)
	binary.LittleEndian.PutUint16(data[34:36], fixtureSampleSize*8)
	copy(data[36:40], "data")
	binary.LittleEndian.PutUint32(data[40:44], uint32(dataBytes))
	for frame := 0; frame < fixtureFrames; frame++ {
		value := int16(6_000)
		if (frame/55)%2 == 1 {
			value = -value
		}
		for channel := 0; channel < fixtureChannels; channel++ {
			offset := 44 + (frame*fixtureChannels+channel)*fixtureSampleSize
			binary.LittleEndian.PutUint16(data[offset:offset+2], uint16(value))
		}
	}
	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
		return err
	}
	return os.WriteFile(path, data, 0o600)
}

func WriteSpeechFixture(path string) error {
	if !filepath.IsAbs(path) || filepath.Clean(path) != path || filepath.Ext(path) != ".webm" {
		return fmt.Errorf("acceptance speech fixture path must be a clean absolute .webm path")
	}
	data, err := base64.StdEncoding.DecodeString(acceptanceSpeechFixtureBase64)
	if err != nil || len(data) != 14_125 ||
		fmt.Sprintf("%x", sha256.Sum256(data)) != acceptanceSpeechFixtureSHA256 {
		return fmt.Errorf("acceptance speech fixture is invalid")
	}
	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
		return err
	}
	return os.WriteFile(path, data, 0o600)
}
